/**
 * Generates a terminal window styled SVG of the GitHub contribution graph,
 * using live data pulled straight from the GitHub GraphQL API.
 *
 * Run by .github/workflows/update-contrib-terminal.yml on a daily schedule.
 * Output: assets/contrib-terminal-dark.svg, assets/contrib-terminal-light.svg
 *
 * Both variants share the same palette as dark.svg / light.svg (generated by
 * generate_profile.py and generate_badges.py), so the whole profile stays on
 * one theme, whichever mode GitHub happens to be rendering in.
 *
 * Env vars required:
 *   GH_USERNAME   github username to fetch contributions for (for example RanaZaid26194)
 *   GH_TOKEN      a token with at least public read access (GITHUB_TOKEN works)
 */

const fs = require("fs");
const path = require("path");
const https = require("https");

// These come from the environment rather than being hard coded, so anyone
// forking this repository only needs to change the workflow's env values
// instead of editing this file directly.
const USERNAME = process.env.GH_USERNAME;
const TOKEN = process.env.GH_TOKEN;

// If this file is executed directly (rather than required as a module by
// something else) and either variable is missing, there is nothing useful
// we can do, so we fail loudly and exit instead of continuing with blanks.
if (require.main === module && (!USERNAME || !TOKEN)) {
  console.error("Missing GH_USERNAME or GH_TOKEN env vars.");
  process.exit(1);
}

// Same palette as THEMES in generate_profile.py, keep these two in sync
// whenever one of them changes.
const THEMES = {
  dark: {
    bg: "#0d1117",
    panel: "#161b22",
    border: "#30363d",
    text: "#c9d1d9",
    muted: "#8b949e",
    key: "#3fb950",
    accent: "#58a6ff",
    warn: "#d29922",
    dot1: "#ff5f56",
    dot2: "#ffbd2e",
    dot3: "#27c93f",
    emptyCell: "#1e2530",
    levels: ["#0e4429", "#006d32", "#26a641", "#39d353"],
  },
  light: {
    bg: "#ffffff",
    panel: "#f6f8fa",
    border: "#d0d7de",
    text: "#1f2328",
    muted: "#59636e",
    key: "#1a7f37",
    accent: "#0969da",
    warn: "#9a6700",
    dot1: "#ff5f56",
    dot2: "#ffbd2e",
    dot3: "#27c93f",
    emptyCell: "#ebedf0",
    levels: ["#9be9a8", "#40c463", "#30a14e", "#216e39"],
  },
};

// This is the GraphQL query sent to GitHub, asking for exactly one year of
// contribution data grouped into weeks, which matches how GitHub itself
// lays out the contribution graph on a profile page.
const query = `
query($login: String!) {
  user(login: $login) {
    contributionsCollection {
      contributionCalendar {
        totalContributions
        weeks {
          contributionDays {
            date
            contributionCount
          }
        }
      }
    }
  }
}`;

function graphqlRequest(query, variables) {
  // A small wrapper around the raw https module so the rest of the script
  // can just await a plain promise instead of dealing with callbacks.
  const body = JSON.stringify({ query, variables });
  const options = {
    hostname: "api.github.com",
    path: "/graphql",
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `bearer ${TOKEN}`,
      "User-Agent": USERNAME,
      "Content-Length": Buffer.byteLength(body),
    },
  };
  return new Promise((resolve, reject) => {
    const req = https.request(options, (res) => {
      let data = "";
      res.on("data", (chunk) => (data += chunk));
      res.on("end", () => {
        try {
          const parsed = JSON.parse(data);
          if (parsed.errors) return reject(new Error(JSON.stringify(parsed.errors)));
          resolve(parsed);
        } catch (e) {
          reject(e);
        }
      });
    });
    req.on("error", reject);
    req.write(body);
    req.end();
  });
}

function computeStats(weeks) {
  // Flattens every week down into one single list of days, since most of
  // the numbers we need (totals, streaks, best day) are easier to work out
  // by walking through the days in plain chronological order.
  const days = weeks.flatMap((w) => w.contributionDays);
  const total = days.reduce((s, d) => s + d.contributionCount, 0);

  // The longest streak is tracked by counting how many days in a row have
  // at least one contribution, and remembering the biggest run we have
  // seen so far as we walk forward through the whole year.
  let longest = 0;
  let running = 0;
  for (const d of days) {
    if (d.contributionCount > 0) {
      running += 1;
      longest = Math.max(longest, running);
    } else {
      running = 0;
    }
  }

  // current streak: walk back from the most recent day
  let current = 0;
  for (let i = days.length - 1; i >= 0; i--) {
    if (days[i].contributionCount > 0) {
      current += 1;
    } else {
      // allow "today" to be a day with zero contributions so far without breaking the streak
      if (i === days.length - 1) continue;
      break;
    }
  }

  // The best single day is simply whichever entry has the highest count,
  // found with one pass over the whole list.
  let best = days[0];
  for (const d of days) {
    if (d.contributionCount > best.contributionCount) best = d;
  }

  const startDate = days[0].date;
  const endDate = days[days.length - 1].date;

  return { total, longest, current, best, startDate, endDate };
}

// Assign each day a heat level from zero to four based on its own count,
// independent of whatever color GitHub's API happens to hand back. This is
// what lets us recolor the grid per theme instead of being stuck with one
// fixed palette.
function levelFor(count, max) {
  // A day with no contributions is always level zero, drawn as an empty
  // cell. Everything else is bucketed into quarters of the busiest day in
  // the whole year, so the shading always adapts to how active this
  // particular year actually was instead of using fixed thresholds.
  if (count <= 0) return 0;
  if (max <= 4) return Math.min(count, 4);
  const q = max / 4;
  if (count <= q) return 1;
  if (count <= q * 2) return 2;
  if (count <= q * 3) return 3;
  return 4;
}

function monthLabelsForWeeks(weeks) {
  // Return { weekIndex: label } for weeks where the month changes
  // We only want to print a month name in the column where that month
  // actually starts, so we remember the last month we saw and only add a
  // label when it changes.
  const labels = {};
  let lastMonth = null;
  weeks.forEach((w, i) => {
    const firstDay = w.contributionDays[0];
    if (!firstDay) return;
    const month = new Date(firstDay.date).getMonth();
    if (month !== lastMonth) {
      labels[i] = new Date(firstDay.date).toLocaleString("en-US", { month: "short" });
      lastMonth = month;
    }
  });
  return labels;
}

function fmtDate(iso) {
  // Turns an ISO date string into the compact MM-DD-YYYY style shown at
  // the bottom of the panel.
  const d = new Date(iso);
  return d.toLocaleDateString("en-US", { year: "numeric", month: "2-digit", day: "2-digit" }).replace(/\//g, "-");
}

function buildSVG(weeks, stats, username, themeName) {
  const t = THEMES[themeName];
  const cell = 11;
  const gap = 3;
  const gridLeft = 46;
  const gridTop = 50;
  const width = gridLeft + weeks.length * (cell + gap) + 20;
  const height = gridTop + 7 * (cell + gap) + 90;

  // The heaviest day in the whole year sets the scale that every other
  // day's shade is measured against, and the month labels are worked out
  // once up front so we know where to place them alongside the grid.
  const maxCount = Math.max(1, ...weeks.flatMap((w) => w.contributionDays.map((d) => d.contributionCount)));
  const monthLabels = monthLabelsForWeeks(weeks);

  // Draws one small rounded square per day, positioned by its week column
  // and day of week row, coloured according to its heat level, with a
  // native tooltip showing the exact date and count on hover.
  let squares = "";
  weeks.forEach((week, wi) => {
    week.contributionDays.forEach((day) => {
      const dow = new Date(day.date).getDay(); // 0 = Sun
      const x = gridLeft + wi * (cell + gap);
      const y = gridTop + dow * (cell + gap);
      const lvl = levelFor(day.contributionCount, maxCount);
      const color = lvl === 0 ? t.emptyCell : t.levels[lvl - 1];
      squares += `<rect x="${x}" y="${y}" width="${cell}" height="${cell}" rx="2" fill="${color}"><title>${day.date}: ${day.contributionCount} contributions</title></rect>\n`;
    });
  });

  // Month labels sit a touch lower, closer to the grid, using the space
  // that was previously left empty right under the titlebar.
  let monthText = "";
  for (const [wi, label] of Object.entries(monthLabels)) {
    const x = gridLeft + Number(wi) * (cell + gap);
    monthText += `<text x="${x}" y="${gridTop - 8}" class="label">${label}</text>\n`;
  }

  // Day of week labels are right aligned just before the grid instead of
  // being pinned flush to the left edge of the canvas.
  const dayLabels = [
    { label: "Mon", dow: 1 },
    { label: "Wed", dow: 3 },
    { label: "Fri", dow: 5 },
  ]
    .map(
      (d) =>
        `<text x="${gridLeft - 8}" y="${gridTop + d.dow * (cell + gap) + cell - 2}" text-anchor="end" class="label">${d.label}</text>`
    )
    .join("\n");

  const footerY = gridTop + 7 * (cell + gap) + 34;

  // The label "current streak " is drawn in an 11px monospace font, and at
  // that size it renders wider than you might expect, so this width needs
  // enough room for the whole phrase plus a small gap before the number
  // that follows it. Without this, the streak number ends up overlapping
  // the tail end of the word "streak" instead of sitting cleanly after it.
  const streakLabelW = 108;

  return `<svg viewBox="0 0 ${width} ${height}" xmlns="http://www.w3.org/2000/svg" font-family="ui-monospace, SFMono-Regular, 'JetBrains Mono', 'Cascadia Code', Menlo, Consolas, monospace">
  <style>
    .bg { fill: ${t.bg}; }
    .frame { fill: none; stroke: ${t.accent}33; stroke-width: 1.5; }
    .titlebar { fill: ${t.panel}; }
    .title { fill: ${t.muted}; font-size: 11px; }
    .label { fill: ${t.muted}; font-size: 9px; }
    .stat-num { fill: ${t.accent}; font-weight: 700; font-size: 12px; }
    .stat-txt { fill: ${t.text}; font-size: 12px; }
    .dim { fill: ${t.muted}; font-size: 11px; }
    .dot { r: 5; }
  </style>

  <rect class="bg" width="${width}" height="${height}" rx="14"/>
  <rect class="frame" x="0.75" y="0.75" width="${width - 1.5}" height="${height - 1.5}" rx="14"/>

  <rect class="titlebar" width="${width}" height="28" rx="14"/>
  <rect x="0" y="14" width="${width}" height="14" fill="${t.panel}"/>
  <circle class="dot" cx="18" cy="14" fill="${t.dot1}"/>
  <circle class="dot" cx="34" cy="14" fill="${t.dot2}"/>
  <circle class="dot" cx="50" cy="14" fill="${t.dot3}"/>
  <text x="${width / 2}" y="18" text-anchor="middle" class="title">${username}@github: ~/contributions --graph</text>

  ${monthText}
  ${dayLabels}
  ${squares}

  <text x="${gridLeft}" y="${footerY}" class="stat-num">${stats.total.toLocaleString()}</text>
  <text x="${gridLeft + stats.total.toLocaleString().length * 7.5 + 6}" y="${footerY}" class="stat-txt"> contributions in the last year</text>

  <text x="${gridLeft}" y="${footerY + 20}" class="dim">current streak </text>
  <text x="${gridLeft + streakLabelW}" y="${footerY + 20}" class="stat-num">${stats.current} days</text>
  <text x="${gridLeft + streakLabelW + (String(stats.current).length + 5) * 7.2 + 6}" y="${footerY + 20}" class="dim"> · longest </text>
  <text x="${gridLeft + streakLabelW + (String(stats.current).length + 5) * 7.2 + 78}" y="${footerY + 20}" class="stat-num">${stats.longest} days</text>

  <text x="${width - 20}" y="${footerY}" text-anchor="end" class="dim">${fmtDate(stats.startDate)} &#8594; ${fmtDate(stats.endDate)}</text>
  <text x="${width - 20}" y="${footerY + 20}" text-anchor="end" class="dim">best day <tspan class="stat-num">${stats.best.contributionCount}</tspan> on ${fmtDate(stats.best.date)}</text>
</svg>`;
}

async function main() {
  // The real entry point, run by the workflow. It fetches this year of
  // contribution data, works out the summary numbers, then writes out one
  // svg per theme into the assets folder.
  const result = await graphqlRequest(query, { login: USERNAME });
  const calendar = result.data.user.contributionsCollection.contributionCalendar;
  const stats = computeStats(calendar.weeks);
  stats.total = calendar.totalContributions;

  const outDir = path.join(__dirname, "..", "assets");
  fs.mkdirSync(outDir, { recursive: true });

  for (const themeName of Object.keys(THEMES)) {
    const svg = buildSVG(calendar.weeks, stats, USERNAME, themeName);
    fs.writeFileSync(path.join(outDir, `contrib-terminal-${themeName}.svg`), svg);
    console.log(`Wrote assets/contrib-terminal-${themeName}.svg`);
  }
  console.log(stats);
}

if (require.main === module) {
  main().catch((err) => {
    console.error(err);
    process.exit(1);
  });
}

module.exports = { THEMES, computeStats, buildSVG };
